using InventoryFlow.Domain.Common;
using InventoryFlow.Domain.Exceptions;

namespace InventoryFlow.Domain.Entities;

/// <summary>An immutable posted single-product transfer between two warehouses.</summary>
public sealed class WarehouseTransfer : Entity<Guid>
{
    public WarehouseTransfer(Guid id, Guid workspaceId, Guid sourceWarehouseId, Guid destinationWarehouseId, Guid productId,
        decimal quantity, string idempotencyKey, Guid sourceInventoryMovementId, Guid destinationInventoryMovementId,
        DateTimeOffset transferredAtUtc) : base(id)
    {
        if (id == Guid.Empty || workspaceId == Guid.Empty || sourceWarehouseId == Guid.Empty || destinationWarehouseId == Guid.Empty ||
            productId == Guid.Empty || sourceInventoryMovementId == Guid.Empty || destinationInventoryMovementId == Guid.Empty)
            throw new DomainException("Warehouse transfer identifiers are required.");
        if (sourceWarehouseId == destinationWarehouseId)
            throw new DomainException("Source and destination warehouses must be different.");
        if (sourceInventoryMovementId == destinationInventoryMovementId)
            throw new DomainException("Warehouse transfer movements must be different.");
        if (transferredAtUtc.Offset != TimeSpan.Zero)
            throw new DomainException("Warehouse transfer time must be in UTC.");

        WorkspaceId = workspaceId;
        SourceWarehouseId = sourceWarehouseId;
        DestinationWarehouseId = destinationWarehouseId;
        ProductId = productId;
        Quantity = InventoryMovement.ValidateQuantity(quantity);
        IdempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
        SourceInventoryMovementId = sourceInventoryMovementId;
        DestinationInventoryMovementId = destinationInventoryMovementId;
        TransferredAtUtc = transferredAtUtc;
    }

    public Guid WorkspaceId { get; private set; }
    public Guid SourceWarehouseId { get; private set; }
    public Guid DestinationWarehouseId { get; private set; }
    public Guid ProductId { get; private set; }
    public decimal Quantity { get; private set; }
    public string IdempotencyKey { get; private set; }
    public Guid SourceInventoryMovementId { get; private set; }
    public Guid DestinationInventoryMovementId { get; private set; }
    public DateTimeOffset TransferredAtUtc { get; private set; }
}

using System.Text.Json.Serialization;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Transfers;

public sealed record RecordWarehouseTransferRequest(Guid SourceWarehouseId, Guid DestinationWarehouseId, Guid ProductId,
    [property: JsonNumberHandling(JsonNumberHandling.AllowReadingFromString)] decimal Quantity, string IdempotencyKey);

public sealed record RecordWarehouseTransferCommand(Guid WorkspaceId, Guid SourceWarehouseId, Guid DestinationWarehouseId,
    Guid ProductId, decimal Quantity, string IdempotencyKey) : MediatR.IRequest<WarehouseTransferResponse?>;

public sealed record ListWarehouseTransfersQuery(Guid WorkspaceId) : MediatR.IRequest<IReadOnlyList<WarehouseTransferResponse>>;

public sealed record WarehouseTransferResponse(Guid Id, Guid SourceWarehouseId, Guid DestinationWarehouseId, Guid ProductId,
    decimal Quantity, Guid SourceInventoryMovementId, Guid DestinationInventoryMovementId, DateTimeOffset TransferredAtUtc)
{
    public static WarehouseTransferResponse From(WarehouseTransfer transfer) => new(transfer.Id, transfer.SourceWarehouseId,
        transfer.DestinationWarehouseId, transfer.ProductId, transfer.Quantity, transfer.SourceInventoryMovementId,
        transfer.DestinationInventoryMovementId, transfer.TransferredAtUtc);
}

public interface IWarehouseTransferService
{
    Task<WarehouseTransfer?> RecordAsync(Guid workspaceId, Guid sourceWarehouseId, Guid destinationWarehouseId, Guid productId,
        decimal quantity, string idempotencyKey, DateTimeOffset transferredAtUtc, CancellationToken cancellationToken);
    Task<IReadOnlyList<WarehouseTransfer>> ListAsync(Guid workspaceId, CancellationToken cancellationToken);
}

using MediatR;

namespace InventoryFlow.Application.Features.Transfers;

public sealed class RecordWarehouseTransferHandler(IWarehouseTransferService service, TimeProvider timeProvider)
    : IRequestHandler<RecordWarehouseTransferCommand, WarehouseTransferResponse?>
{
    public async Task<WarehouseTransferResponse?> Handle(RecordWarehouseTransferCommand request, CancellationToken cancellationToken)
    {
        var transfer = await service.RecordAsync(request.WorkspaceId, request.SourceWarehouseId, request.DestinationWarehouseId,
            request.ProductId, request.Quantity, request.IdempotencyKey, timeProvider.GetUtcNow(), cancellationToken);
        return transfer is null ? null : WarehouseTransferResponse.From(transfer);
    }
}

public sealed class ListWarehouseTransfersHandler(IWarehouseTransferService service)
    : IRequestHandler<ListWarehouseTransfersQuery, IReadOnlyList<WarehouseTransferResponse>>
{
    public async Task<IReadOnlyList<WarehouseTransferResponse>> Handle(ListWarehouseTransfersQuery request,
        CancellationToken cancellationToken) =>
        (await service.ListAsync(request.WorkspaceId, cancellationToken)).Select(WarehouseTransferResponse.From).ToArray();
}

using FluentValidation;
using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Transfers;

public sealed class RecordWarehouseTransferCommandValidator : AbstractValidator<RecordWarehouseTransferCommand>
{
    public RecordWarehouseTransferCommandValidator()
    {
        RuleFor(x => x.WorkspaceId).NotEmpty();
        RuleFor(x => x.SourceWarehouseId).NotEmpty();
        RuleFor(x => x.DestinationWarehouseId).NotEmpty().NotEqual(x => x.SourceWarehouseId)
            .WithMessage("Source and destination warehouses must be different.");
        RuleFor(x => x.ProductId).NotEmpty();
        RuleFor(x => x.Quantity).GreaterThan(0m).Must(quantity => decimal.Round(quantity, 4) == quantity)
            .WithMessage("Quantity must have at most four decimal places.")
            .LessThanOrEqualTo(InventoryMovement.MaxQuantity).WithMessage("Quantity must not exceed 99999999999999.9999.");
        RuleFor(x => x.IdempotencyKey).NotEmpty().MaximumLength(InventoryMovement.IdempotencyKeyMaxLength);
    }
}

using InventoryFlow.Domain.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace InventoryFlow.Infrastructure.Persistence.Configurations;

public sealed class WarehouseTransferConfiguration : IEntityTypeConfiguration<WarehouseTransfer>
{
    public void Configure(EntityTypeBuilder<WarehouseTransfer> builder)
    {
        builder.ToTable("WarehouseTransfers");
        builder.HasKey(transfer => transfer.Id);
        builder.Property(transfer => transfer.Quantity).HasPrecision(18, 4).IsRequired();
        builder.Property(transfer => transfer.IdempotencyKey).HasMaxLength(InventoryMovement.IdempotencyKeyMaxLength).IsRequired();
        builder.Property(transfer => transfer.TransferredAtUtc).IsRequired();
        builder.HasIndex(transfer => new { transfer.WorkspaceId, transfer.IdempotencyKey }).IsUnique();
        builder.HasIndex(transfer => transfer.SourceInventoryMovementId).IsUnique();
        builder.HasIndex(transfer => transfer.DestinationInventoryMovementId).IsUnique();
        builder.HasIndex(transfer => new { transfer.WorkspaceId, transfer.TransferredAtUtc, transfer.Id });
        builder.HasOne<Workspace>().WithMany().HasForeignKey(transfer => transfer.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
        builder.HasOne<Warehouse>().WithMany().HasForeignKey(transfer => transfer.SourceWarehouseId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<Warehouse>().WithMany().HasForeignKey(transfer => transfer.DestinationWarehouseId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<Product>().WithMany().HasForeignKey(transfer => transfer.ProductId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(transfer => transfer.SourceInventoryMovementId).OnDelete(DeleteBehavior.Restrict);
        builder.HasOne<InventoryMovement>().WithMany().HasForeignKey(transfer => transfer.DestinationInventoryMovementId).OnDelete(DeleteBehavior.Restrict);
    }
}

using System.Data;
using InventoryFlow.Application.Features.Transfers;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Domain.Exceptions;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Transfers;

/// <summary>Posts immutable warehouse transfers with a serializable, two-balance ledger update.</summary>
public sealed class EfWarehouseTransferService(ApplicationDbContext dbContext) : IWarehouseTransferService
{
    public async Task<WarehouseTransfer?> RecordAsync(Guid workspaceId, Guid sourceWarehouseId, Guid destinationWarehouseId,
        Guid productId, decimal quantity, string idempotencyKey, DateTimeOffset transferredAtUtc, CancellationToken cancellationToken)
    {
        quantity = InventoryMovement.ValidateQuantity(quantity);
        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
        if (sourceWarehouseId == destinationWarehouseId)
            throw new DomainException("Source and destination warehouses must be different.");

        var strategy = dbContext.Database.CreateExecutionStrategy();
        return await strategy.ExecuteAsync(async () =>
        {
            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
            var existing = await dbContext.WarehouseTransfers.SingleOrDefaultAsync(transfer => transfer.WorkspaceId == workspaceId &&
                transfer.IdempotencyKey == idempotencyKey, cancellationToken);
            if (existing is not null)
            {
                await transaction.CommitAsync(cancellationToken);
                return existing;
            }

            var productExists = await dbContext.Products.AnyAsync(product => product.Id == productId &&
                product.WorkspaceId == workspaceId && product.ArchivedAtUtc == null, cancellationToken);
            var sourceExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == sourceWarehouseId &&
                warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
            var destinationExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == destinationWarehouseId &&
                warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
            if (!productExists || !sourceExists || !destinationExists)
            {
                await transaction.RollbackAsync(cancellationToken);
                return null;
            }

            // Every transfer acquires both key/range locks in the same warehouse-ID order, including reverse transfers.
            var firstWarehouseId = sourceWarehouseId.CompareTo(destinationWarehouseId) < 0 ? sourceWarehouseId : destinationWarehouseId;
            var secondWarehouseId = firstWarehouseId == sourceWarehouseId ? destinationWarehouseId : sourceWarehouseId;
            var firstBalance = await LockBalanceAsync(workspaceId, firstWarehouseId, productId, cancellationToken);
            var secondBalance = await LockBalanceAsync(workspaceId, secondWarehouseId, productId, cancellationToken);

            var sourceBalance = sourceWarehouseId == firstWarehouseId ? firstBalance : secondBalance;
            var destinationBalance = destinationWarehouseId == firstWarehouseId ? firstBalance : secondBalance;
            sourceBalance.Apply(-quantity);
            destinationBalance.Apply(quantity);

            var transferId = Guid.NewGuid();
            var sourceMovement = new InventoryMovement(Guid.NewGuid(), workspaceId, sourceWarehouseId, productId,
                InventoryMovementType.Issue, quantity, $"{transferId:N}:issue", sourceBalance.Quantity, transferredAtUtc);
            var destinationMovement = new InventoryMovement(Guid.NewGuid(), workspaceId, destinationWarehouseId, productId,
                InventoryMovementType.Receipt, quantity, $"{transferId:N}:receipt", destinationBalance.Quantity, transferredAtUtc);
            var transfer = new WarehouseTransfer(transferId, workspaceId, sourceWarehouseId, destinationWarehouseId, productId,
                quantity, idempotencyKey, sourceMovement.Id, destinationMovement.Id, transferredAtUtc);

            dbContext.InventoryMovements.AddRange(sourceMovement, destinationMovement);
            dbContext.WarehouseTransfers.Add(transfer);
            await dbContext.SaveChangesAsync(cancellationToken);
            await transaction.CommitAsync(cancellationToken);
            return transfer;
        });
    }

    public async Task<IReadOnlyList<WarehouseTransfer>> ListAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.WarehouseTransfers.AsNoTracking().Where(transfer => transfer.WorkspaceId == workspaceId)
            .OrderByDescending(transfer => transfer.TransferredAtUtc).ThenByDescending(transfer => transfer.Id)
            .ToListAsync(cancellationToken);

    private async Task<InventoryBalance> LockBalanceAsync(Guid workspaceId, Guid warehouseId, Guid productId,
        CancellationToken cancellationToken)
    {
        var balance = await dbContext.InventoryBalances.FromSqlInterpolated($"""
            SELECT * FROM [InventoryBalances] WITH (UPDLOCK, HOLDLOCK)
            WHERE [WorkspaceId] = {workspaceId} AND [WarehouseId] = {warehouseId} AND [ProductId] = {productId}
            """).SingleOrDefaultAsync(cancellationToken);
        if (balance is not null) return balance;

        balance = new InventoryBalance(workspaceId, warehouseId, productId, 0m);
        dbContext.InventoryBalances.Add(balance);
        return balance;
    }
}

